-- Top 100 public vocabulary content v1, part 1.
-- Split into smaller files to keep D1 migration statements manageable.


UPDATE core_vocabulary SET word = 'the', meaning_zh = '这；那；这个；那个', definition_en = 'used before a noun to talk about a specific person, thing, or group', primary_part_of_speech = 'determiner', phonetic_us = '/ðə, ði/', phonetic_uk = '/ðə, ðiː/', updated_at = CURRENT_TIMESTAMP WHERE id = 'the';
UPDATE vocabulary_pronunciations SET phonetic = CASE accent WHEN 'us' THEN '/ðə, ði/' WHEN 'uk' THEN '/ðə, ðiː/' ELSE phonetic END, phonetic_source = 'manual-curation', updated_at = CURRENT_TIMESTAMP WHERE vocabulary_id = 'the' AND accent IN ('us', 'uk');

